template:
/// Returns the inner value doubled if Some, or 0 if None.
pub fn double_or_zero(opt: Option<i32>) -> i32 {
    match opt {
        [[SLOT some_arm]]
        [[SLOT none_arm]]
    }
}

fn main() {
    println!("Some(5) -> {}", double_or_zero(Some(5)));
    println!("None    -> {}", double_or_zero(None));
}
